code.C:
#include <stdio.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int T, A, B;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d", &A, &B);
        printf("%d\n", gcd(A, B));
    }
    return 0;
}

